import React, { useEffect, useState } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import { 
  ArrowLeft, 
  User, 
  Calendar, 
  Clock, 
  AlertTriangle,
  CheckCircle,
  Phone,
  Mail,
  FileText,
  Tag,
  Activity,
  Save,
  UserCheck,
  CheckSquare
} from 'lucide-react';
import { useTask } from '../contexts/TaskContext';
import SLAStatusBadge from '../components/UI/SLAStatusBadge';
import PriorityBadge from '../components/UI/PriorityBadge';
import NotificationIndicators from '../components/UI/NotificationIndicators';
import DynamicTaskForm from '../components/Forms/DynamicTaskForm';

const TaskDetail = () => {
  const { taskId } = useParams();
  const navigate = useNavigate();
  const { 
    selectedTask, 
    selectedTaskLoading, 
    selectedTaskError,
    claimTask, 
    completeTask,
    fetchTaskDetails 
  } = useTask();

  const [showForm, setShowForm] = useState(false);
  const [actionLoading, setActionLoading] = useState(null);

  useEffect(() => {
    if (taskId) {
      fetchTaskDetails(taskId);
    }
  }, [taskId, fetchTaskDetails]);

  const handleClaimTask = async () => {
    try {
      setActionLoading('claim');
      await claimTask(taskId, 'current-user');
      navigate(-1); // Go back to previous page
    } catch (error) {
      console.error('Failed to claim task:', error);
    } finally {
      setActionLoading(null);
    }
  };

  const handleCompleteTask = async (variables) => {
    try {
      setActionLoading('complete');
      await completeTask(taskId, variables);
      navigate(-1); // Go back to previous page
    } catch (error) {
      console.error('Failed to complete task:', error);
    } finally {
      setActionLoading(null);
    }
  };

  const handleQuickComplete = async () => {
    await handleCompleteTask({});
  };

  if (selectedTaskLoading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary-600"></div>
      </div>
    );
  }

  if (selectedTaskError) {
    return (
      <div className="bg-red-50 border border-red-200 rounded-lg p-4">
        <div className="flex items-center justify-between">
          <div className="flex items-center">
            <AlertTriangle className="w-5 h-5 text-red-600 mr-2" />
            <p className="text-red-800">{selectedTaskError}</p>
          </div>
          <button
            onClick={() => navigate(-1)}
            className="text-red-600 hover:text-red-800"
          >
            ×
          </button>
        </div>
      </div>
    );
  }

  if (!selectedTask) {
    return (
      <div className="text-center py-12">
        <FileText className="w-12 h-12 text-gray-400 mx-auto mb-4" />
        <p className="text-gray-500">Task not found</p>
      </div>
    );
  }

  const { variables } = selectedTask;
  const customer = variables?.customer || {};
  const complaint = variables?.complaint || {};
  const sla = variables?.sla || {};
  const notification = variables?.notification || {};

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center space-x-4">
          <button
            onClick={() => navigate(-1)}
            className="flex items-center space-x-2 text-gray-600 hover:text-gray-900"
          >
            <ArrowLeft className="w-5 h-5" />
            <span>Back</span>
          </button>
          <div>
            <h1 className="text-2xl font-bold text-gray-900">Task Details</h1>
            <p className="text-gray-600">{selectedTask.name}</p>
          </div>
        </div>

        <div className="flex items-center space-x-3">
          {!selectedTask.assignee && (
            <button
              onClick={handleClaimTask}
              disabled={actionLoading === 'claim'}
              className="flex items-center space-x-2 bg-green-600 text-white px-4 py-2 rounded-lg hover:bg-green-700 transition-colors disabled:opacity-50"
            >
              {actionLoading === 'claim' ? (
                <>
                  <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-white"></div>
                  <span>Claiming...</span>
                </>
              ) : (
                <>
                  <UserCheck className="w-4 h-4" />
                  <span>Claim Task</span>
                </>
              )}
            </button>
          )}

          {selectedTask.assignee && (
            <>
              <button
                onClick={() => setShowForm(!showForm)}
                className="flex items-center space-x-2 bg-primary-600 text-white px-4 py-2 rounded-lg hover:bg-primary-700 transition-colors"
              >
                <FileText className="w-4 h-4" />
                <span>{showForm ? 'Hide Form' : 'Complete Task'}</span>
              </button>

              {!showForm && (
                <button
                  onClick={handleQuickComplete}
                  disabled={actionLoading === 'complete'}
                  className="flex items-center space-x-2 bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 transition-colors disabled:opacity-50"
                >
                  {actionLoading === 'complete' ? (
                    <>
                      <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-white"></div>
                      <span>Completing...</span>
                    </>
                  ) : (
                    <>
                      <CheckSquare className="w-4 h-4" />
                      <span>Quick Complete</span>
                    </>
                  )}
                </button>
              )}
            </>
          )}
        </div>
      </div>

      {/* Task Information Cards */}
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Task Details */}
        <div className="lg:col-span-2 space-y-6">
          {/* Basic Task Info */}
          <div className="bg-white rounded-lg shadow p-6">
            <h2 className="text-lg font-semibold text-gray-900 mb-4">Task Information</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-gray-700">Task ID</label>
                <p className="mt-1 text-sm text-gray-900">{selectedTask.id}</p>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700">Task Name</label>
                <p className="mt-1 text-sm text-gray-900">{selectedTask.name}</p>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700">Process Instance</label>
                <p className="mt-1 text-sm text-gray-900">{selectedTask.processInstanceId}</p>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700">Assignee</label>
                <p className="mt-1 text-sm text-gray-900">
                  {selectedTask.assignee || 'Unassigned'}
                </p>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700">Created Date</label>
                <p className="mt-1 text-sm text-gray-900">{selectedTask.createdAt}</p>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700">Priority</label>
                <div className="mt-1">
                  <PriorityBadge priority={selectedTask.priority} />
                </div>
              </div>
            </div>
          </div>

          {/* Customer Information */}
          <div className="bg-white rounded-lg shadow p-6">
            <h2 className="text-lg font-semibold text-gray-900 mb-4">Customer Information</h2>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className="block text-sm font-medium text-gray-700">Name</label>
                <p className="mt-1 text-sm text-gray-900">{customer.name || 'N/A'}</p>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700">Email</label>
                <div className="mt-1 flex items-center">
                  <Mail className="w-4 h-4 text-gray-400 mr-2" />
                  <span className="text-sm text-gray-900">{customer.email || 'N/A'}</span>
                </div>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700">Phone</label>
                <div className="mt-1 flex items-center">
                  <Phone className="w-4 h-4 text-gray-400 mr-2" />
                  <span className="text-sm text-gray-900">{customer.phone || 'N/A'}</span>
                </div>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700">Account Number</label>
                <p className="mt-1 text-sm text-gray-900">{customer.accountNumber || 'N/A'}</p>
              </div>
            </div>
          </div>

          {/* Complaint Details */}
          <div className="bg-white rounded-lg shadow p-6">
            <h2 className="text-lg font-semibold text-gray-900 mb-4">Complaint Details</h2>
            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700">Complaint ID</label>
                <div className="mt-1 flex items-center">
                  <Tag className="w-4 h-4 text-gray-400 mr-2" />
                  <span className="text-sm text-gray-900">{complaint.id || 'N/A'}</span>
                </div>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700">Channel</label>
                <p className="mt-1 text-sm text-gray-900">{complaint.channel || 'N/A'}</p>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700">Description</label>
                <p className="mt-1 text-sm text-gray-900 bg-gray-50 p-3 rounded-lg">
                  {complaint.description || 'No description provided'}
                </p>
              </div>
            </div>
          </div>

          {/* Case History */}
          {variables?.caseHistory && (
            <div className="bg-white rounded-lg shadow p-6">
              <h2 className="text-lg font-semibold text-gray-900 mb-4">Case History</h2>
              <div className="bg-gray-50 p-4 rounded-lg">
                <pre className="text-sm text-gray-700 whitespace-pre-wrap">
                  {variables.caseHistory}
                </pre>
              </div>
            </div>
          )}
        </div>

        {/* Sidebar */}
        <div className="space-y-6">
          {/* SLA Information */}
          <div className="bg-white rounded-lg shadow p-6">
            <h2 className="text-lg font-semibold text-gray-900 mb-4">SLA Information</h2>
            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-gray-700">Status</label>
                <div className="mt-1">
                  <SLAStatusBadge status={selectedTask.slaStatus} />
                </div>
              </div>
              {sla.deadline && (
                <div>
                  <label className="block text-sm font-medium text-gray-700">Deadline</label>
                  <div className="mt-1 flex items-center">
                    <Clock className="w-4 h-4 text-gray-400 mr-2" />
                    <span className="text-sm text-gray-900">
                      {new Date(sla.deadline).toLocaleString()}
                    </span>
                  </div>
                </div>
              )}
              {sla.breached && (
                <div className="bg-red-50 border border-red-200 rounded-lg p-3">
                  <div className="flex items-center">
                    <AlertTriangle className="w-4 h-4 text-red-600 mr-2" />
                    <span className="text-sm text-red-800">SLA Breached</span>
                  </div>
                  {sla.breachedAt && (
                    <p className="text-xs text-red-600 mt-1">
                      Breached at: {new Date(sla.breachedAt).toLocaleString()}
                    </p>
                  )}
                </div>
              )}
              <div>
                <label className="block text-sm font-medium text-gray-700">Reminder Count</label>
                <p className="mt-1 text-sm text-gray-900">{sla.reminderCount || 0}</p>
              </div>
              <div>
                <label className="block text-sm font-medium text-gray-700">Escalation Level</label>
                <p className="mt-1 text-sm text-gray-900">{sla.escalationLevel || 0}</p>
              </div>
            </div>
          </div>

          {/* Notification Status */}
          <div className="bg-white rounded-lg shadow p-6">
            <h2 className="text-lg font-semibold text-gray-900 mb-4">Notifications</h2>
            <NotificationIndicators notification={notification} />
          </div>

          {/* Process Variables */}
          <div className="bg-white rounded-lg shadow p-6">
            <h2 className="text-lg font-semibold text-gray-900 mb-4">Process Variables</h2>
            <div className="space-y-2">
              {Object.entries(variables || {}).map(([key, value]) => {
                if (typeof value === 'object' && value !== null) {
                  return null; // Skip objects, they're displayed above
                }
                return (
                  <div key={key} className="flex justify-between text-sm">
                    <span className="font-medium text-gray-700">{key}:</span>
                    <span className="text-gray-900">{String(value)}</span>
                  </div>
                );
              })}
            </div>
          </div>
        </div>
      </div>

      {/* Dynamic Task Form */}
      {showForm && (
        <div className="bg-white rounded-lg shadow p-6">
          <h2 className="text-lg font-semibold text-gray-900 mb-4">Complete Task</h2>
          <DynamicTaskForm
            taskDefinitionKey={selectedTask.definitionKey}
            taskName={selectedTask.name}
            onSubmit={handleCompleteTask}
            onCancel={() => setShowForm(false)}
            loading={actionLoading === 'complete'}
          />
        </div>
      )}
    </div>
  );
};

export default TaskDetail;
